    return res.status(404).render('error', {
      title: '404 - Not Found',
      statusCode: 404,
      message: 'URL not found.',
    });
  }

  res.render('stats', {
    title: `Stats: ${stats.url.code} - URL Shortener`,
    baseUrl: config.baseUrl,
    stats,
    days,
  });
});

module.exports = router;

