}

.stat-urls {
  word-break: break-all;
}

.stat-urls p {
  margin-bottom: 0.375rem;
}

.stat-urls a {
  color: var(--color-primary);
}

.original-url-display {
  font-size: 0.9rem;
}

.period-selector {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

/* === Chart (CSS bar chart) === */
.chart-container {
  display: flex;
  flex-direction: column;
  gap: 0.375rem;
}

.chart-bar-row {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.chart-label {
  width: 50px;
  font-size: 0.8rem;
  color: var(--color-text-secondary);
  text-align: right;
  flex-shrink: 0;
}

.chart-bar-container {
  flex: 1;
  background: var(--color-bg);
  border-radius: 4px;
  height: 24px;
  overflow: hidden;
}

.chart-bar {
  height: 100%;
  background: var(--color-bar);
  border-radius: 4px;
  min-width: 2px;
  transition: width 0.3s ease;
}

.chart-value {
  width: 36px;
  font-size: 0.85rem;
  font-weight: 600;
  flex-shrink: 0;
}

/* === Empty state === */
.empty-state {
  text-align: center;
  padding: 3rem 1.5rem;
}

.empty-state p {
  color: var(--color-text-secondary);
  margin-bottom: 1rem;
}

.empty-state-text {
  text-align: center;
  color: var(--color-text-secondary);
  padding: 2rem 0;
}

/* === Error page === */
.error-page {
  text-align: center;
  padding: 4rem 1.5rem;
}

.error-page h1 {
  font-size: 4rem;
  color: var(--color-primary);
  margin-bottom: 0.5rem;
}

.error-page p {
  color: var(--color-text-secondary);
  margin-bottom: 1.5rem;
  font-size: 1.1rem;
}

/* === Responsive === */
@media (max-width: 640px) {
  .form-row {
    flex-direction: column;
    gap: 0;
  }

  .stats-grid {
    grid-template-columns: 1fr;
  }

  .actions-cell {
    flex-direction: column;
  }
}

